"use client";

import { useScoreStore } from "@/store/useScoreStore";

// A quick helper to translate our numeric points (0,1,2,3,4) into tennis/padel terms
const translatePoints = (points: number) => {
  const pointMap: Record<number, string> = { 0: "0", 1: "15", 2: "30", 3: "40", 4: "Ad" };
  return pointMap[points] || "0";
};

export default function Home() {
  // Grab our state and functions from the Zustand store
  const { team1Points, team2Points, team1Games, team2Games, addPoint, resetMatch } = useScoreStore();

  return (
    <main className="flex min-h-screen flex-col items-center justify-center bg-zinc-900 text-white p-4">
      <h1 className="text-4xl font-bold mb-12 text-emerald-400">Padel Scoreboard</h1>

      {/* Scoreboard Container */}
      <div className="flex gap-8 md:gap-16 w-full max-w-3xl justify-center mb-12">
        
        {/* Team 1 Card */}
        <div className="flex flex-col items-center bg-zinc-800 p-8 rounded-2xl shadow-lg w-full">
          <h2 className="text-2xl font-semibold mb-4 text-zinc-400">Team 1</h2>
          <div className="text-7xl font-black mb-2">{translatePoints(team1Points)}</div>
          <div className="text-xl text-zinc-500 mb-6">Games: <span className="text-emerald-400 font-bold">{team1Games}</span></div>
          <button 
            onClick={() => addPoint('team1')}
            className="w-full bg-emerald-600 hover:bg-emerald-500 text-white py-3 rounded-lg font-bold transition-colors"
          >
            + Point
          </button>
        </div>

        {/* Team 2 Card */}
        <div className="flex flex-col items-center bg-zinc-800 p-8 rounded-2xl shadow-lg w-full">
          <h2 className="text-2xl font-semibold mb-4 text-zinc-400">Team 2</h2>
          <div className="text-7xl font-black mb-2">{translatePoints(team2Points)}</div>
          <div className="text-xl text-zinc-500 mb-6">Games: <span className="text-emerald-400 font-bold">{team2Games}</span></div>
          <button 
            onClick={() => addPoint('team2')}
            className="w-full bg-emerald-600 hover:bg-emerald-500 text-white py-3 rounded-lg font-bold transition-colors"
          >
            + Point
          </button>
        </div>

      </div>

      <button 
        onClick={resetMatch}
        className="text-red-400 hover:text-red-300 font-semibold underline underline-offset-4"
      >
        Reset Match
      </button>
    </main>
  );
}