import { create } from 'zustand';

type Team = 'team1' | 'team2';

interface ScoreState {
  team1Points: number;
  team2Points: number;
  team1Games: number;
  team2Games: number;
  addPoint: (team: Team) => void;
  resetMatch: () => void;
}

export const useScoreStore = create<ScoreState>((set) => ({
  team1Points: 0,
  team2Points: 0,
  team1Games: 0,
  team2Games: 0,

  addPoint: (team) => set((state) => {
    let t1P = state.team1Points;
    let t2P = state.team2Points;

    if (team === 'team1') t1P++;
    else t2P++;

    // Win Game Logic (Needs 4 points, must win by 2)
    if (t1P > 3 && t1P - t2P >= 2) {
      return { team1Games: state.team1Games + 1, team1Points: 0, team2Points: 0 };
    }
    if (t2P > 3 && t2P - t1P >= 2) {
      return { team2Games: state.team2Games + 1, team1Points: 0, team2Points: 0 };
    }

    // Deuce / Advantage Logic: If both reach Advantage (4 points), reset back to Deuce (3 points)
    if (t1P === 4 && t2P === 4) {
      return { team1Points: 3, team2Points: 3 };
    }

    return { team1Points: t1P, team2Points: t2P };
  }),

  resetMatch: () => set({ team1Points: 0, team2Points: 0, team1Games: 0, team2Games: 0 }),
}));